describe("drain sink abort behavior", () => {
  it("should pass the abort error value (not just true) to read when abort is an Error", (done) => {
    const abortError = new Error("custom abort error");

    const readCalls: any[] = [];
    const source = (end: any, cb: (end: any, data?: any) => void) => {
      readCalls.push(end);
      if (end) {
        cb(end, null);
        return;
      }
      // Provide data synchronously
      cb(null, "item");
    };

    const op = (_data: any) => false; // Always return false

    const doneCallback = (err: any) => {
      // Original: read(abort || true, ...) => read(abortError, ...) => source called with abortError => done(abortError)
      // Mutated: read(true, ...) => source called with true => done(null) because true === true
      expect(err).toBe(abortError);
      done();
    };

    const sink = drain(op, doneCallback);
    sink.abort(abortError);
    sink(source);
  });
});
